#!/usr/bin/env python3
from pathlib import Path
import runpy
import sys
import os

SOURCE = '"""Greedy conditional-correlation feature selection.\n\nThe selected set is grown by the increase in ridge-regularized explained\nvariance of the target.  The inverse of the selected correlation block is\nupdated with a Schur complement, so no candidate-specific matrix inverse is\nformed.\n"""\nfrom __future__ import annotations\n\nimport argparse\nimport json\nfrom pathlib import Path\nfrom typing import Any\n\nimport numpy as np\n\n\ndef _validate(correlation: Any, target_correlation: Any, k: int, ridge: float) -> tuple[np.ndarray, np.ndarray, int, float]:\n    R = np.asarray(correlation, dtype=np.float64)\n    r = np.asarray(target_correlation, dtype=np.float64)\n    if R.ndim != 2 or R.shape[0] != R.shape[1]:\n        raise ValueError("correlation must be a square matrix")\n    p = R.shape[0]\n    if r.ndim != 1 or r.shape[0] != p:\n        raise ValueError("target_correlation must have one entry per feature")\n    if not np.all(np.isfinite(R)) or not np.all(np.isfinite(r)):\n        raise ValueError("correlations must be finite")\n    if not isinstance(k, (int, np.integer)) or isinstance(k, bool) or not (0 <= int(k) <= p):\n        raise ValueError("k must be an integer between zero and the number of features")\n    if not np.isscalar(ridge) or not np.isfinite(ridge) or float(ridge) < 0:\n        raise ValueError("ridge must be a finite nonnegative scalar")\n    # Correlation estimates may have tiny roundoff asymmetry.  Using the\n    # symmetric part makes the update deterministic and avoids an indefinite\n    # block solely because of input ordering.\n    R = (R + R.T) * 0.5\n    return R, r, int(k), float(ridge)\n\n\ndef greedy_select(correlation, target_correlation, k, *, ridge=1e-8) -> list[int]:\n    """Select ``k`` features by greedy conditional target association.\n\n    At each step feature ``j`` receives the ridge-regularized partial-\n    correlation gain\n\n    ``(r_j - R[j,S] R[S,S]⁻¹ r[S])² / (R[j,j]+ridge - R[j,S]R[S,S]⁻¹R[S,j])``.\n\n    The inverse block is initialized for the first feature and enlarged with a\n    rank-one Schur update after every choice.  Candidates are considered in\n    ascending original-index order, making exact and numerical ties stable.\n    The returned indices are in selection order.\n    """\n    R, r, k, ridge = _validate(correlation, target_correlation, k, ridge)\n    p = R.shape[0]\n    if k == 0:\n        return []\n    remaining = np.arange(p, dtype=np.int64)\n    selected: list[int] = []\n    inv = np.empty((0, 0), dtype=np.float64)\n    r_selected = np.empty(0, dtype=np.float64)\n\n    for _ in range(k):\n        if not selected:\n            # A one-dimensional ridge block has a closed form.  Candidate\n            # scores use its own diagonal, not an assumed unit diagonal.\n            denom = np.maximum(np.diag(R) + ridge, np.finfo(float).tiny)\n            scores = (r * r) / denom\n            best_pos = int(np.argmax(scores))\n            best = int(remaining[best_pos])\n            inv = np.array([[1.0 / denom[best]]], dtype=np.float64)\n            r_selected = np.array([r[best]], dtype=np.float64)\n        else:\n            S = np.asarray(selected, dtype=np.int64)\n            C = R[np.ix_(S, remaining)]\n            # inv @ C computes all candidate projections at once; only O(p|S|)\n            # temporary storage is needed.\n            projected = inv @ C\n            feature_var = np.diag(R)[remaining] + ridge - np.sum(C * projected, axis=0)\n            feature_var = np.maximum(feature_var, np.finfo(float).eps)\n            residual_target = r[remaining] - projected.T @ r_selected\n            scores = (residual_target * residual_target) / feature_var\n            best_pos = int(np.argmax(scores))\n            best = int(remaining[best_pos])\n\n            b = C[:, best_pos]\n            v = inv @ b\n            schur = float(R[best, best] + ridge - b @ v)\n            schur = max(schur, np.finfo(float).eps)\n            n_old = inv.shape[0]\n            expanded = np.empty((n_old + 1, n_old + 1), dtype=np.float64)\n            expanded[:n_old, :n_old] = inv + np.outer(v, v) / schur\n            expanded[:n_old, n_old] = -v / schur\n            expanded[n_old, :n_old] = -v / schur\n            expanded[n_old, n_old] = 1.0 / schur\n            inv = expanded\n            r_selected = np.append(r_selected, r[best])\n\n        selected.append(best)\n        remaining = np.delete(remaining, best_pos)\n    return selected\n\n\ndef _cli(argv: list[str] | None = None) -> None:\n    parser = argparse.ArgumentParser(description=__doc__)\n    parser.add_argument("--input", type=Path, default=Path("selector_input.npz"))\n    parser.add_argument("--output", type=Path, default=Path("outputs/selection.json"))\n    args = parser.parse_args(argv)\n    with np.load(args.input) as data:\n        R = data["correlation"]\n        r = data["target_correlation"]\n    config_path = args.input.with_name("selector_config.json")\n    config = json.loads(config_path.read_text(encoding="utf-8"))\n    selected = greedy_select(R, r, int(config["k"]), ridge=float(config.get("ridge", 1e-8)))\n    args.output.parent.mkdir(parents=True, exist_ok=True)\n    args.output.write_text(json.dumps({"selected_indices": selected}, indent=2) + "\\n", encoding="utf-8")\n\n\nif __name__ == "__main__":\n    _cli()\n'

def main():
    workspace = Path(sys.argv[1]) if len(sys.argv) > 1 else Path.cwd()
    (workspace / 'selector.py').write_text(SOURCE, encoding="utf-8")
    os.chdir(workspace)
    sys.argv = [str(workspace / 'selector.py')]
    runpy.run_path(str(workspace / 'selector.py'), run_name="__main__")

if __name__ == "__main__":
    main()
